package ir.tahamohamadi.portfolio.project; import ir.tahamohamadi.common.domain.ContentStatus; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import ir.tahamohamadi.media.asset.MediaAsset; import jakarta.persistence.*; import lombok.*; import java.time.LocalDate;
@Entity @Table(name="portfolio_project") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class PortfolioProject extends AuditedSoftDeletableEntity { @Column(name="project_key",nullable=false) private String projectKey; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="cover_media_id") private MediaAsset coverMedia; @Enumerated(EnumType.STRING) @Column(nullable=false) private ContentStatus status; @Column(name="started_on") private LocalDate startedOn; @Column(name="ended_on") private LocalDate endedOn; @Column(name="project_url") private String projectUrl; @Column(name="repository_url") private String repositoryUrl; @Column(name="sort_order",nullable=false) private int sortOrder; }
